const now = new Date();
const timestamp = now.toISOString().replace(/[:.]/g, '-').slice(0, 19);
const backupName = `n3-backup-${timestamp}`;
return [{ json: { backup_name: backupName, timestamp: now.toISOString(), tables: ['products_master', 'inventory_master', 'orders_unified', 'research_results', 'admin_tasks', 'global_settings', 'logistics_providers', 'performance_snapshots'] } }];

const config = $node['🔐 初期化'].json;
const tableStats = $node['📊 テーブル統計取得'].json;
const productsCount = $node['📦 商品数カウント'].json?.products_count || 0;
const ordersCount = $node['🛒 受注数カウント'].json?.orders_count || 0;
const backupSummary = {
  backup_name: config.backup_name,
  timestamp: config.timestamp,
  stats: {
    products: parseInt(productsCount),
    orders: parseInt(ordersCount),
    tables: Array.isArray(tableStats) ? tableStats.length : 1
  },
  table_details: tableStats
};
return [{ json: backupSummary }];

